index c55c40c88bc8..f86ca79b90b7 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
@@ -2229,6 +2229,17 @@ Instruction *InstCombinerImpl::visitCallInst(CallInst &CI) {
         return BitOp;
     }

+    // fshl(X, 0, Y) --> shl X, Y when Y is known to be in [0, BitWidth)
+    // fshl(X, undef, Y) --> shl X, Y when Y is known to be in [0, BitWidth)
+    if (match(Op1, m_ZeroInt()) || match(Op1, m_Undef())) {
+      Value *ShAmt = II->getArgOperand(2);
+      ConstantRange ShAmtRange =
+          computeConstantRangeIncludingKnownBits(ShAmt, /*ForSigned=*/false,
+                                                 SQ.getWithInstruction(II));
+      if (!ShAmtRange.isFullSet() && ShAmtRange.getUpper().ule(BitWidth))
+        return BinaryOperator::CreateShl(Op0, ShAmt);
+    }
+
     // Left or right might be masked.
     if (SimplifyDemandedInstructionBits(*II))
       return &CI;

